local spellInfos = {}

local function addSpell(spellId, name, magickaCost, ...)

    local rawEffectInfos = {...}
    local effectInfos = {}

    for i, effect in ipairs(rawEffectInfos) do

        effectInfos[i] = {
            id = effect[1], -- tes3.effect
            attribute = effect[2], -- tes3.attribute
            skill = effect[3], -- tes3.skill
            rangeType = effect[4], -- tes3.effectRange
            radius = effect[5], -- 0 to 50
            durationMult = effect[6], -- 1 to 4
            durationFlat = effect[7], -- 1 to 300
            tier = effect[8], -- 0.0 to 4.0
        }

    end

    spellInfos[spellId] = {
        name = name,
        magickaCost = magickaCost, -- autoCalc when nil
        effectInfos = effectInfos,
    }

end

